"use strict";parserFactory.register("nhvnovels.com",()=>new BlogusParser),parserFactory.register("pienovels.com",()=>new BlogusParser);class BlogusParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelectorAll(".chapter-item[data-url]");if(t.length>0){let e=[...t].map(e=>({sourceUrl:e.getAttribute("data-url"),title:e.querySelector(".chapter-title")?.textContent?.trim(),isIncludeable:"premium"!==e.getAttribute("data-type")}));return e.reverse(),e}let r=[];for(let t of e.querySelectorAll(".chapter-section .paid-class2[href]")){let e=t.querySelector(".ch-ul-li p")?.textContent?.trim();r.push({sourceUrl:t.href,title:e,isIncludeable:!1})}for(let t of e.querySelectorAll(".chapter-section .dropdown-content a[href]:not(.paid-class2)")){let e=t.querySelector(".ch-ul-li p")?.textContent?.trim();e&&r.push({sourceUrl:t.href,title:e,isIncludeable:!0})}return r.reverse(),r}findContent(e){return e.querySelector(".chapter-text")}extractTitleImpl(e){return e.querySelector(".novel-title")||e.querySelector(".title")}extractAuthor(e){let t=e.querySelector(".badge-author")?.textContent?.trim();return t||super.extractAuthor(e)}extractDescription(e){return e.querySelector(".novel-description, .description")?.textContent?.trim()}findChapterTitle(e){return e.querySelector(".chapter-title")}findCoverImageUrl(e){let t=e.querySelector(".novel-image img")||e.querySelector(".single-left-img .main-img-single");return t?.src||null}removeUnwantedElementsFromContentElement(e){util.removeElements(e.querySelectorAll(".tsl-preview, .recommendation, .code-block")),super.removeUnwantedElementsFromContentElement(e)}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".novel-header, .single-new-novel")]}extractSubject(e){return[...e.querySelectorAll(".badge.genre, .single-tags")].map(e=>e.textContent?.trim()).join(", ")}}